unitsize(1inch);
pair P,Q,R;
P = (0,0);
Q= (1,0);
R = (0,1);
draw (P--Q--R--P,linewidth(0.9));
draw(rightanglemark(Q,P,R,3));
label("$P$",P,S);
label("$Q$",Q,S);
label("$R$",R,N);
[/asy]

